import { useRouter } from 'expo-router';
import { View } from 'react-native';

import { useKangurMobileI18n } from '../i18n/kangurMobileI18n';
import {
  useKangurMobileLessonCheckpoints,
} from '../lessons/useKangurMobileLessonCheckpoints';
import {
  KangurMobileLinkButton as LinkButton,
  KangurMobileScrollScreen,
} from '../shared/KangurMobileUi';
import {
  DUELS_ROUTE,
} from './daily-plan-primitives';
import { useKangurMobileDailyPlanAssignments } from './useKangurMobileDailyPlanAssignments';
import {
  useKangurMobileDailyPlanBadges,
} from './useKangurMobileDailyPlanBadges';
import { useKangurMobileDailyPlanDuels } from './useKangurMobileDailyPlanDuels';
import { useKangurMobileDailyPlan } from './useKangurMobileDailyPlan';
import { useKangurMobileDailyPlanLessonMastery } from './useKangurMobileDailyPlanLessonMastery';
import { DailyPlanSummaryCard } from './components/DailyPlanSummaryCard';
import { DailyPlanFocusSection } from './components/DailyPlanFocusSection';
import { DailyPlanBadgesSection } from './components/DailyPlanBadgesSection';
import { DailyPlanDuelsSection } from './components/DailyPlanDuelsSection';
import { DailyPlanAssignmentsSection } from './components/DailyPlanAssignmentsSection';
import { DailyPlanMasterySection } from './components/DailyPlanMasterySection';
import { DailyPlanCheckpointsSection } from './components/DailyPlanCheckpointsSection';
import { DailyPlanResultsSection } from './components/DailyPlanResultsSection';
import { createKangurDuelsHref } from '../duels/duelsHref';

export function KangurDailyPlanScreen(): React.JSX.Element {
  const { copy, locale } = useKangurMobileI18n();
  const router = useRouter();
  const lessonCheckpoints = useKangurMobileLessonCheckpoints({ limit: 2 });
  const lessonMastery = useKangurMobileDailyPlanLessonMastery();
  const dailyPlanBadges = useKangurMobileDailyPlanBadges();
  const dailyPlanAssignments = useKangurMobileDailyPlanAssignments();
  const {
    authError,
    displayName,
    isAuthenticated,
    isLoadingAuth,
    isLoading,
    recentResultItems,
    refresh,
    scoreError,
    signIn,
    strongestFocus,
    supportsLearnerCredentials,
    weakestFocus,
  } = useKangurMobileDailyPlan();
  const duelPlan = useKangurMobileDailyPlanDuels();
  const weakestLesson = lessonMastery.weakest[0] ?? null;
  const strongestLesson = lessonMastery.strongest[0] ?? null;

  let lessonFocusSummary: string | null = null;
  if (weakestLesson !== null) {
    lessonFocusSummary = copy({
      de: `Fokus für heute: ${weakestLesson.title} braucht noch eine kurze Wiederholung, bevor du wieder Tempo aufnimmst.`,
      en: `Focus for today: ${weakestLesson.title} still needs a short review before you build pace again.`,
      pl: `Fokus na dziś: ${weakestLesson.title} potrzebuje jeszcze krótkiej powtórki, zanim znowu wejdziesz w tempo.`,
    });
  } else if (strongestLesson !== null) {
    lessonFocusSummary = copy({
      de: `Stabile Stärke: ${strongestLesson.title} hält das Niveau und eignet sich für einen kurzen sicheren Einstieg.`,
      en: `Stable strength: ${strongestLesson.title} is holding its level and works well for a short confident start.`,
      pl: `Stabilna mocna strona: ${strongestLesson.title} trzyma poziom i nadaje się na krótki, pewny start.`,
    });
  }

  const openDuelSession = (sessionId: string): void => {
    router.replace(createKangurDuelsHref({ sessionId }));
  };

  return (
    <KangurMobileScrollScreen
      contentContainerStyle={{
        gap: 18,
        paddingHorizontal: 20,
        paddingVertical: 24,
      }}
    >
        <View style={{ gap: 14 }}>
          <LinkButton
            href='/'
            label={copy({
              de: 'Zurück',
              en: 'Back',
              pl: 'Wróć',
            })}
          />

          <DailyPlanSummaryCard
            assignmentsCount={dailyPlanAssignments.assignmentItems.length}
            authError={authError}
            copy={copy}
            displayName={displayName}
            isAuthenticated={isAuthenticated}
            isLoadingAuth={isLoadingAuth}
            lessonsCount={lessonMastery.trackedLessons}
            refresh={() => refresh()}
            resultsCount={recentResultItems.length}
            signIn={() => signIn()}
            supportsLearnerCredentials={supportsLearnerCredentials}
          />

          <DailyPlanFocusSection
            copy={copy}
            isAuthenticated={isAuthenticated}
            isLoading={isLoading}
            scoreError={scoreError}
            strongestFocus={strongestFocus}
            weakestFocus={weakestFocus}
          />

          <DailyPlanBadgesSection
            copy={copy}
            recentBadges={dailyPlanBadges.recentBadges}
            remainingBadges={dailyPlanBadges.remainingBadges}
            totalBadges={dailyPlanBadges.totalBadges}
            unlockedBadges={dailyPlanBadges.unlockedBadges}
          />

          <DailyPlanDuelsSection
            copy={copy}
            duelPlan={duelPlan}
            locale={locale}
            openDuelSession={openDuelSession}
          />

          <DailyPlanAssignmentsSection
            assignmentItems={dailyPlanAssignments.assignmentItems}
            copy={copy}
          />

          <DailyPlanMasterySection
            copy={copy}
            lessonFocusSummary={lessonFocusSummary}
            lessonMastery={lessonMastery}
          />

          <DailyPlanCheckpointsSection
            copy={copy}
            lessonCheckpoints={lessonCheckpoints}
          />

          <DailyPlanResultsSection
            copy={copy}
            isAuthenticated={isAuthenticated}
            isLoading={isLoading}
            recentResultItems={recentResultItems}
            scoreError={scoreError}
          />
        </View>
    </KangurMobileScrollScreen>
  );
}

import { Text, View } from 'react-native';
import { KangurMobileCard as Card, KangurMobileLinkButton as LinkButton, KangurMobilePill as Pill } from '../../shared/KangurMobileUi';
import { DailyPlanBadgeChip, PROFILE_ROUTE } from '../daily-plan-primitives';
import { type KangurMobileCopy } from '../../i18n/kangurMobileI18n';

interface DailyPlanBadgesSectionProps {
    copy: KangurMobileCopy;
    unlockedBadges: number;
    totalBadges: number;
    remainingBadges: number;
    recentBadges: any[];
}

export function DailyPlanBadgesSection({
    copy,
    unlockedBadges,
    totalBadges,
    remainingBadges,
    recentBadges,
}: DailyPlanBadgesSectionProps): React.JSX.Element {
    return (
        <Card>
            <View style={{ gap: 4 }}>
                <Text style={{ color: '#64748b', fontSize: 12, fontWeight: '700' }}>
                    {copy({ de: 'Abzeichen', en: 'Badges', pl: 'Odznaki' })}
                </Text>
                <Text style={{ color: '#0f172a', fontSize: 20, fontWeight: '800' }}>
                    {copy({ de: 'Abzeichen-Zentrale', en: 'Badge hub', pl: 'Centrum odznak' })}
                </Text>
                <Text style={{ color: '#475569', lineHeight: 22 }}>
                    {copy({ de: 'Behalte im Blick, was schon freigeschaltet ist und welches lokale Ziel am nächsten an der nächsten Abzeichenstufe liegt.', en: 'Keep track of what is already unlocked and which local goal is closest to the next badge threshold.', pl: 'Śledź, co jest już odblokowane i który lokalny cel jest najbliżej kolejnego progu odznaki.' })}
                </Text>
            </View>

            <View style={{ flexDirection: 'row', flexWrap: 'wrap', gap: 8 }}>
                <Pill
                    label={copy({ de: `Freigeschaltet ${unlockedBadges}/${totalBadges}`, en: `Unlocked ${unlockedBadges}/${totalBadges}`, pl: `Odblokowane ${unlockedBadges}/${totalBadges}` })}
                    tone={{ backgroundColor: '#eef2ff', borderColor: '#c7d2fe', textColor: '#4338ca' }}
                />
                <Pill
                    label={copy({ de: `Offen ${remainingBadges}`, en: `Remaining ${remainingBadges}`, pl: `Do zdobycia ${remainingBadges}` })}
                    tone={{ backgroundColor: '#fffbeb', borderColor: '#fde68a', textColor: '#b45309' }}
                />
            </View>

            {recentBadges.length === 0 ? (
                <Text style={{ color: '#475569', lineHeight: 22 }}>
                    {copy({ de: 'Es gibt noch keine lokal freigeschalteten Abzeichen. Schließe Lektionen, Trainings oder Spiele ab, damit sie hier erscheinen.', en: 'There are no locally unlocked badges yet. Finish lessons, practice runs, or games so they appear here.', pl: 'Nie ma jeszcze lokalnie odblokowanych odznak. Ukończ lekcje, treningi albo gry, aby pojawiły się tutaj.' })}
                </Text>
            ) : (
                <View style={{ gap: 12 }}>
                    <Text style={{ color: '#0f172a', fontSize: 16, fontWeight: '700' }}>
                        {copy({ de: 'Zuletzt freigeschaltet', en: 'Recently unlocked', pl: 'Ostatnio odblokowane' })}
                    </Text>
                    <View style={{ flexDirection: 'row', flexWrap: 'wrap', gap: 8 }}>
                        {recentBadges.map((item) => (
                            <DailyPlanBadgeChip key={item.id} item={item} />
                        ))}
                    </View>
                </View>
            )}

            <LinkButton href={PROFILE_ROUTE} label={copy({ de: 'Profil und Abzeichen öffnen', en: 'Open profile and badges', pl: 'Otwórz profil i odznaki' })} />
        </Card>
    );
}

import { Text, View } from 'react-native';
import { KangurMobileCard as Card, KangurMobileLinkButton as LinkButton } from '../../shared/KangurMobileUi';
import { LessonCheckpointRow, LESSONS_ROUTE } from '../daily-plan-primitives';
import { type KangurMobileCopy } from '../../i18n/kangurMobileI18n';
import { type UseKangurMobileLessonCheckpointsResult, type KangurMobileLessonCheckpointItem } from '../useKangurMobileLessonCheckpoints';

interface DailyPlanCheckpointsSectionProps {
    copy: KangurMobileCopy;
    lessonCheckpoints: UseKangurMobileLessonCheckpointsResult;
}

export function DailyPlanCheckpointsSection({
    copy,
    lessonCheckpoints,
}: DailyPlanCheckpointsSectionProps): React.JSX.Element {
    return (
        <Card>
            <View style={{ gap: 4 }}>
                <Text style={{ color: '#0f172a', fontSize: 20, fontWeight: '800' }}>
                    {copy({ de: 'Letzte Lektions-Checkpoints', en: 'Recent lesson checkpoints', pl: 'Ostatnie checkpointy lekcji' })}
                </Text>
                <Text style={{ color: '#475569', lineHeight: 22 }}>
                    {copy({ de: 'Die letzten lokal gespeicherten Lektionen helfen dir, vor dem nächsten Training genau an der letzten Stelle weiterzumachen.', en: 'The most recently saved lessons help you resume exactly from the last saved point before the next practice block.', pl: 'Ostatnio zapisane lekcje pomagają wrócić dokładnie do ostatniego miejsca przed kolejnym blokiem treningowym.' })}
                </Text>
            </View>

            {lessonCheckpoints.recentCheckpoints.length === 0 ? (
                <Text style={{ color: '#475569', lineHeight: 22 }}>
                    {copy({ de: 'Es gibt noch keine gespeicherten Checkpoints. Öffne eine Lektion und speichere den ersten Stand, damit sie hier erscheinen.', en: 'There are no saved checkpoints yet. Open a lesson and save the first state so they appear here.', pl: 'Nie ma jeszcze zapisanych checkpointów. Otwórz lekcję i zapisz pierwszy stan, aby pojawiły się tutaj.' })}
                </Text>
            ) : (
                <View style={{ gap: 12 }}>
                    {lessonCheckpoints.recentCheckpoints.map((item: KangurMobileLessonCheckpointItem) => (
                        <LessonCheckpointRow key={item.componentId} item={item} />
                    ))}
                    <LinkButton href={LESSONS_ROUTE} label={copy({ de: 'Lektionen öffnen', en: 'Open lessons', pl: 'Otwórz lekcje' })} />
                </View>
            )}
        </Card>
    );
}

import { Text, View } from 'react-native';
import {
  KangurMobileCard as Card,
  KangurMobileInsetPanel as InsetPanel,
  KangurMobileLinkButton as LinkButton,
  KangurMobilePendingActionButton,
  KangurMobilePill as Pill,
} from '../../shared/KangurMobileUi';
import { DUELS_ROUTE } from '../daily-plan-primitives';
import { type KangurMobileCopy, type KangurMobileLocale } from '../../i18n/kangurMobileI18n';
import { formatKangurMobileScoreDateTime } from '../../scores/mobileScoreSummary';
import {
  type KangurDuelOpponentEntry,
  type KangurDuelLeaderboardEntry,
} from '@kangur/contracts/kangur-duels';
import { type UseKangurMobileLearnerDuelsSummaryResult } from '../../duels/useKangurMobileLearnerDuelsSummary';

export interface DailyPlanDuelsSectionProps {
  copy: KangurMobileCopy;
  locale: string;
  duelPlan: UseKangurMobileLearnerDuelsSummaryResult;
  openDuelSession: (sessionId: string) => void;
}

function OpponentItem({
  opponent,
  copy,
  locale,
  duelPlan,
  openDuelSession,
}: {
  opponent: KangurDuelOpponentEntry;
  copy: KangurMobileCopy;
  locale: string;
  duelPlan: UseKangurMobileLearnerDuelsSummaryResult;
  openDuelSession: (sessionId: string) => void;
}): React.JSX.Element {
  return (
    <InsetPanel gap={8}>
      <Text style={{ color: '#0f172a', fontSize: 16, fontWeight: '800' }}>{opponent.displayName}</Text>
      <Text style={{ color: '#64748b', fontSize: 12, lineHeight: 18 }}>
        {copy({
          de: `Letztes Duell ${formatKangurMobileScoreDateTime(opponent.lastPlayedAt, locale as KangurMobileLocale)}`,
          en: `Last duel ${formatKangurMobileScoreDateTime(opponent.lastPlayedAt, locale as KangurMobileLocale)}`,
          pl: `Ostatni pojedynek ${formatKangurMobileScoreDateTime(opponent.lastPlayedAt, locale as KangurMobileLocale)}`,
        })}
      </Text>
      <KangurMobilePendingActionButton
        horizontalPadding={14}
        label={copy({ de: 'Schneller Rückkampf', en: 'Quick rematch', pl: 'Szybki rewanż' })}
        onPress={async () => {
          const sessionId = await duelPlan.createRematch(opponent.learnerId);
          if (sessionId) openDuelSession(sessionId);
        }}
        pending={duelPlan.pendingOpponentLearnerId === opponent.learnerId}
        pendingLabel={copy({ de: 'Rückkampf wird gesendet...', en: 'Sending rematch...', pl: 'Wysyłanie rewanżu...' })}
      />
    </InsetPanel>
  );
}

function CurrentEntryPanel({
  copy,
  rank,
  entry,
}: {
  copy: KangurMobileCopy;
  rank: number | null;
  entry: KangurDuelLeaderboardEntry;
}): React.JSX.Element {
  return (
    <InsetPanel gap={8} style={{ borderColor: '#bfdbfe', backgroundColor: '#eff6ff' }}>
      <Text style={{ color: '#1d4ed8', fontSize: 12, fontWeight: '800' }}>
        {copy({ de: 'DEIN DUELLSTAND', en: 'YOUR DUEL SNAPSHOT', pl: 'TWÓJ WYNIK W POJEDYNKACH' })}
      </Text>
      <Text style={{ color: '#0f172a', fontSize: 18, fontWeight: '800' }}>
        #{rank ?? 0} {entry.displayName}
      </Text>
      <Text style={{ color: '#475569', fontSize: 14, lineHeight: 20 }}>
        {copy({
          de: `Siege ${entry.wins} • Niederlagen ${entry.losses} • Unentschieden ${entry.ties}`,
          en: `Wins ${entry.wins} • Losses ${entry.losses} • Ties ${entry.ties}`,
          pl: `Wygrane ${entry.wins} • Porażki ${entry.losses} • Remisy ${entry.ties}`,
        })}
      </Text>
    </InsetPanel>
  );
}

export function DailyPlanDuelsSection({
  copy,
  locale,
  duelPlan,
  openDuelSession,
}: DailyPlanDuelsSectionProps): React.JSX.Element {
  const { opponents, currentRank, currentEntry, isRestoringAuth, isLoading, isAuthenticated, error, actionError } = duelPlan;

  if (isRestoringAuth || isLoading) {
    return (
      <Card>
        <Text style={{ color: '#475569', lineHeight: 22 }}>
          {copy({ de: 'Der heutige Duellstand wird geladen...', en: 'Loading today’s duel standing...', pl: 'Ładujemy dzisiejszy stan pojedynków...' })}
        </Text>
      </Card>
    );
  }

  if (!isAuthenticated) {
    return (
      <Card>
        <Text style={{ color: '#475569', lineHeight: 22 }}>
          {copy({ de: 'Melde dich an, um hier deinen Duellstand zu sehen.', en: 'Sign in to see duel standing.', pl: 'Zaloguj się, aby zobaczyć tutaj stan w pojedynkach.' })}
        </Text>
      </Card>
    );
  }

  if (error) {
    return (
      <Card>
        <View style={{ gap: 10 }}>
          <Text style={{ color: '#b91c1c', lineHeight: 20 }}>{error}</Text>
          <LinkButton label={copy({ de: 'Duelle aktualisieren', en: 'Refresh duels', pl: 'Odśwież pojedynki' })} onPress={() => { void duelPlan.refresh(); }} />
        </View>
      </Card>
    );
  }

  return (
    <Card>
      <View style={{ gap: 4 }}>
        <Text style={{ color: '#64748b', fontSize: 12, fontWeight: '700' }}>{copy({ de: 'Duelle für heute', en: 'Duels for today', pl: 'Pojedynki na dziś' })}</Text>
        <Text style={{ color: '#0f172a', fontSize: 20, fontWeight: '800' }}>{copy({ de: 'Schneller Rückweg zu Rivalen', en: 'Quick return to rivals', pl: 'Szybki powrót do rywali' })}</Text>
      </View>
      <View style={{ flexDirection: 'row', flexWrap: 'wrap', gap: 8 }}>
        <Pill label={copy({ de: `Rivalen ${opponents.length}`, en: `Rivals ${opponents.length}`, pl: `Rywale ${opponents.length}` })} tone={{ backgroundColor: '#eef2ff', borderColor: '#c7d2fe', textColor: '#4338ca' }} />
        <Pill label={(currentRank !== null && currentRank !== 0) ? copy({ de: `Deine Position #${currentRank}`, en: `Your rank #${currentRank}`, pl: `Twoja pozycja #${currentRank}` }) : copy({ de: 'Wartet auf Sichtbarkeit', en: 'Waiting for visibility', pl: 'Czeka na widoczność' })} tone={{ backgroundColor: '#ecfdf5', borderColor: '#a7f3d0', textColor: '#047857' }} />
      </View>
      <View style={{ gap: 12 }}>
        {currentEntry !== null ? <CurrentEntryPanel copy={copy} rank={currentRank} entry={currentEntry} /> : <Text style={{ color: '#475569', lineHeight: 22 }}>{copy({ de: 'Dein Konto ist nicht sichtbar.', en: 'Your account is not visible.', pl: 'Twoje konto jest niewidoczne.' })}</Text>}
        {actionError && <Text style={{ color: '#b91c1c', lineHeight: 20 }}>{actionError}</Text>}
        {opponents.length === 0 ? <Text style={{ color: '#475569', lineHeight: 22 }}>{copy({ de: 'Keine Rivalen.', en: 'No rivals.', pl: 'Brak rywali.' })}</Text> : opponents.map((opponent) => <OpponentItem key={opponent.learnerId} opponent={opponent} copy={copy} locale={locale} duelPlan={duelPlan} openDuelSession={openDuelSession} />)}
        <LinkButton href={DUELS_ROUTE} label={copy({ de: 'Duelle öffnen', en: 'Open duels', pl: 'Otwórz pojedynki' })} stretch />
      </View>
    </Card>
  );
}

import { Text, View } from 'react-native';
import { KangurMobileCard as Card } from '../../shared/KangurMobileUi';
import { FocusCard } from '../daily-plan-primitives';
import { type KangurMobileCopy } from '../../i18n/kangurMobileI18n';
import { type KangurMobileDailyPlanFocus } from '../useKangurMobileDailyPlan';

interface DailyPlanFocusSectionProps {
  copy: KangurMobileCopy;
  isLoading: boolean;
  isAuthenticated: boolean;
  scoreError: string | null;
  weakestFocus: KangurMobileDailyPlanFocus | null;
  strongestFocus: KangurMobileDailyPlanFocus | null;
}

export function DailyPlanFocusSection({
  copy,
  isLoading,
  isAuthenticated,
  scoreError,
  weakestFocus,
  strongestFocus,
}: DailyPlanFocusSectionProps): React.JSX.Element {
  if (isLoading) {
    return (
      <Card>
        <Text style={{ color: '#475569' }}>
          {copy({
            de: 'Der ergebnisbasierte Fokus wird geladen...',
            en: 'Loading score-based focus...',
            pl: 'Ładujemy fokus oparty na wynikach...',
          })}
        </Text>
      </Card>
    );
  }

  if (scoreError !== null && scoreError !== '') {
    return (
      <Card>
        <Text style={{ color: '#b91c1c', lineHeight: 20 }}>{scoreError}</Text>
      </Card>
    );
  }

  if (!isAuthenticated) {
    return (
      <Card>
        <Text style={{ color: '#475569', lineHeight: 22 }}>
          {copy({
            de: 'Melde dich an, um Hinweise für den stärksten und schwächsten Modus freizuschalten.',
            en: 'Sign in to unlock guidance for the strongest and weakest modes.',
            pl: 'Zaloguj się, aby odblokować wskazówki dla najmocniejszego i najsłabszego trybu.',
          })}
        </Text>
      </Card>
    );
  }

  if (weakestFocus === null && strongestFocus === null) {
    return (
      <Card>
        <Text style={{ color: '#475569', lineHeight: 22 }}>
          {copy({
            de: 'Schließe einen Lauf ab, um den ersten Trainingsfokus aufzubauen.',
            en: 'Finish one run to build the first training focus.',
            pl: 'Ukończ jedną serię, aby zbudować pierwszy fokus treningowy.',
          })}
        </Text>
      </Card>
    );
  }

  return (
    <Card>
      <Text style={{ color: '#0f172a', fontSize: 20, fontWeight: '800' }}>
        {copy({ de: 'Trainingsfokus', en: 'Training focus', pl: 'Fokus treningowy' })}
      </Text>
      <View style={{ gap: 12 }}>
        {weakestFocus !== null && (
          <FocusCard
            accentColor='#b91c1c'
            description={copy({
              de: 'Das ist aktuell der schwächste Bereich in deinen Ergebnissen. Zacznij od krótkiej celowanej serii, a potem wróć do pasującej lekcji, wenn es nötig ist.',
              en: 'This is currently the weakest area in your results. Start with a short targeted run and then return to the matching lesson if needed.',
              pl: 'To obecnie najsłabszy obszar w Twoich wynikach. Zacznij od krótkiej celowanej serii, a potem wróć do pasującej lekcji, jeśli będzie trzeba.',
            })}
            historyHref={weakestFocus.historyHref}
            lessonHref={weakestFocus.lessonHref}
            operation={weakestFocus.operation}
            practiceHref={weakestFocus.practiceHref}
            title={copy({ de: 'Zum Wiederholen', en: 'Needs review', pl: 'Do powtórki' })}
          />
        )}
        {strongestFocus !== null && (
          <FocusCard
            accentColor='#047857'
            description={copy({
              de: 'Dieser Modus ist gerade am stabilsten. Nutze ihn für einen schnellen Selbstvertrauensschub oder ein kurzes Aufwärmen.',
              en: 'This mode is the most stable right now. Use it for a quick confidence boost or a light warm-up.',
              pl: 'Ten tryb jest teraz najbardziej stabilny. Użyj go do szybkiego podbicia pewności albo lekkiej rozgrzewki.',
            })}
            historyHref={strongestFocus.historyHref}
            lessonHref={strongestFocus.lessonHref}
            operation={strongestFocus.operation}
            practiceHref={strongestFocus.practiceHref}
            title={copy({ de: 'Stärkster Modus', en: 'Strongest mode', pl: 'Najmocniejszy tryb' })}
          />
        )}
      </View>
    </Card>
  );
}

import { Text, View } from 'react-native';
import { KangurMobileCard as Card, KangurMobileLinkButton as LinkButton } from '../../shared/KangurMobileUi';
import { RecentResultRow } from '../daily-plan-primitives';
import { type KangurMobileCopy } from '../../i18n/kangurMobileI18n';
import { createKangurResultsHref } from '../../scores/resultsHref';
import { type KangurMobileDailyPlanRecentResultItem } from '../useKangurMobileDailyPlan';

interface DailyPlanResultsSectionProps {
    copy: KangurMobileCopy;
    isLoading: boolean;
    isAuthenticated: boolean;
    scoreError: string | null;
    recentResultItems: KangurMobileDailyPlanRecentResultItem[];
}

export function DailyPlanResultsSection({
    copy,
    isLoading,
    isAuthenticated,
    scoreError,
    recentResultItems,
}: DailyPlanResultsSectionProps): React.JSX.Element {
    const renderContent = () => {
        if (isLoading) {
            return (
                <Text style={{ color: '#475569' }}>
                    {copy({ de: 'Die letzten Ergebnisse werden geladen...', en: 'Loading recent results...', pl: 'Ładujemy ostatnie wyniki...' })}
                </Text>
            );
        }
        if (!isAuthenticated) {
            return (
                <Text style={{ color: '#475569', lineHeight: 22 }}>
                    {copy({ de: 'Melde dich an, um hier Ergebnisse zu sehen.', en: 'Sign in to see results here.', pl: 'Zaloguj się, aby zobaczyć tutaj wyniki.' })}
                </Text>
            );
        }
        if (scoreError !== null && scoreError !== '') {
            return <Text style={{ color: '#b91c1c', lineHeight: 20 }}>{scoreError}</Text>;
        }
        if (recentResultItems.length === 0) {
            return (
                <Text style={{ color: '#475569', lineHeight: 22 }}>
                    {copy({ de: 'Es gibt hier noch keine Ergebnisse. Schließe einen Lauf ab, um diesen Bereich zu füllen.', en: 'There are no results here yet. Finish one run to fill this section.', pl: 'Nie ma tu jeszcze wyników. Ukończ jedną serię, aby wypełnić tę sekcję.' })}
                </Text>
            );
        }
        return (
            <View style={{ gap: 12 }}>
                {recentResultItems.map(({ result, historyHref, lessonHref, practiceHref }) => (
                    <RecentResultRow key={result.id} result={result} historyHref={historyHref} lessonHref={lessonHref} practiceHref={practiceHref} />
                ))}
            </View>
        );
    };

    return (
        <Card>
            <View style={{ flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center', gap: 12 }}>
                <Text style={{ color: '#0f172a', fontSize: 20, fontWeight: '800' }}>
                    {copy({ de: 'Ergebniszentrale', en: 'Results hub', pl: 'Centrum wyników' })}
                </Text>
                <LinkButton href={createKangurResultsHref()} label={copy({ de: 'Vollständigen Verlauf öffnen', en: 'Open full history', pl: 'Otwórz pełną historię' })} />
            </View>
            {renderContent()}
        </Card>
    );
}

